mapper.select:
select count(1) from( select a.courier_num, 1 AS dummy from lkt_express_delivery a left join lkt_express b on a.express_id = b.id left join lkt_order o on a.sNo = o.sNo left join lkt_order_details d on a.order_details_id = d.id left join lkt_product_list p on d.p_id = p.id left join lkt_mch m on p.mch_id = m.id
a.courier_num,
) num
